css:
.loader { width: 70px; height: 70px; display: grid; place-items: center; }
.flower-loader {
  overflow: hidden;
  position: relative;
  text-indent: -9999px;
  display: inline-block;
  width: 16px;
  height: 16px;
  background: #ee9966;
  border-radius: 100%;
  box-shadow: white 0 0 15px 0, #448855 -12px -12px 0 4px, #448855 12px -12px 0 4px, #448855 12px 12px 0 4px, #448855 -12px 12px 0 4px;
  animation: flowerPinwheel 5s infinite ease-in-out;
  transform-origin: 50% 50%;
}
@keyframes flowerPinwheel {
  0% { transform: rotate(0deg); box-shadow: white 0 0 15px 0, #448855 -12px -12px 0 4px, #448855 12px -12px 0 4px, #448855 12px 12px 0 4px, #448855 -12px 12px 0 4px; }
  50% { transform: rotate(1080deg); box-shadow: white 0 0 15px 0, #448855 12px 12px 0 4px, #448855 -12px 12px 0 4px, #448855 -12px -12px 0 4px, #448855 12px -12px 0 4px; }
}
